INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Madras', 'attendance', 'Attendance > Consequence: More than 3 P grades means not eligible for IDDD, Dual Degree upgradation, PhD upgradation, YRF, or honours.');
